import{_ as t,o as a,c as o,a0 as r}from"./chunks/framework.B3sz4m_N.js";const n=""+new URL("../report/agentic-techniques-01-executive-summary.png",import.meta.url).href,p=JSON.parse(`{"title":"Executive Summary","description":"Key findings from analysing the Agentic Engineering Book against the Dark Factory workflow — what works, what's missing, and the four highest-leverage improvements.","frontmatter":{"title":"Executive Summary","description":"Key findings from analysing the Agentic Engineering Book against the Dark Factory workflow — what works, what's missing, and the four highest-leverage improvements."},"headers":[],"relativePath":"reports/agentic-engineering-techniques/01-executive-summary.md","filePath":"reports/agentic-engineering-techniques/01-executive-summary.md"}`),i={name:"reports/agentic-engineering-techniques/01-executive-summary.md"};function s(l,e,d,c,u,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<figure class="report-section-image-wrapper" aria-labelledby="fig-exec-summary-caption"><img src="'+n+'" alt="A compass resting on a hand-drawn map of interconnected nodes" loading="lazy" class="report-section-image"><figcaption id="fig-exec-summary-caption">Navigating the landscape of agentic engineering techniques</figcaption></figure><h2 id="_1-executive-summary" tabindex="-1">1. Executive Summary <a class="header-anchor" href="#_1-executive-summary" aria-label="Permalink to &quot;1. Executive Summary&quot;">​</a></h2><p>The <a href="https://jayminwest.com/agentic-engineering-book" target="_blank" rel="noreferrer">Agentic Engineering Book</a> describes a comprehensive framework for building agentic systems organised around four pillars — <strong>Prompt</strong>, <strong>Model</strong>, <strong>Context</strong>, and <strong>Tool Use</strong> — with supporting chapters on Patterns, Practices, and Mental Models.</p><h3 id="what-the-workflow-already-does-well" tabindex="-1">What the workflow already does well <a class="header-anchor" href="#what-the-workflow-already-does-well" aria-label="Permalink to &quot;What the workflow already does well&quot;">​</a></h3><p>The Dark Factory multi-agent research workflow demonstrates strong fundamentals across three of the book&#39;s four core prompt principles:</p><ul><li><strong>Clarity over cleverness</strong> — skills use explicit role definitions, scoped focus areas, and unambiguous constraints</li><li><strong>Structure reduces variance</strong> — every skill follows a consistent pattern (Role, Focus, Do Not, Required Output Structure)</li><li><strong>Constraints enable creativity</strong> — &quot;You Focus ONLY On&quot; and &quot;You DO NOT&quot; sections provide tight scope boundaries</li></ul><p>The evaluation rubric (15-criteria, 75-point scoring model) is ahead of many practitioners described in the book.</p><h3 id="where-the-significant-gaps-are" tabindex="-1">Where the significant gaps are <a class="header-anchor" href="#where-the-significant-gaps-are" aria-label="Permalink to &quot;Where the significant gaps are&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Gap</th><th>Severity</th><th>Core issue</th></tr></thead><tbody><tr><td>No parallel agent execution</td><td>High</td><td>Independent agents run sequentially, doubling wall-clock time</td></tr><tr><td>No context isolation</td><td>High</td><td>All agent outputs accumulate in one context window, degrading reconciliation quality</td></tr><tr><td>No few-shot examples in skills</td><td>High</td><td>Models infer output format from descriptions alone; inconsistent results across runs</td></tr><tr><td>No uncertainty handling</td><td>High</td><td>Skills don&#39;t specify when to ask vs proceed, leading to arbitrary decisions on ambiguous inputs</td></tr><tr><td>No evaluation practice</td><td>High</td><td>Rubric exists but is not applied; no eval cases, no systematic measurement</td></tr><tr><td>No self-improvement loop</td><td>Medium</td><td>When a skill produces subpar output, improvement is ad-hoc</td></tr></tbody></table><h3 id="the-four-highest-leverage-improvements" tabindex="-1">The four highest-leverage improvements <a class="header-anchor" href="#the-four-highest-leverage-improvements" aria-label="Permalink to &quot;The four highest-leverage improvements&quot;">​</a></h3><ol><li><p><strong>Parallelise independent agents</strong> — architect, dev-lead, devops, and governance can run simultaneously. Estimated 50% wall-clock time reduction with zero quality risk.</p></li><li><p><strong>Add few-shot examples to skills</strong> — one concrete input/output pair per skill establishes format, tone, and depth more reliably than instructions alone. Highest impact on output consistency.</p></li><li><p><strong>Start evaluating with golden examples</strong> — even 3–5 known-good input/output pairs per skill transforms the workflow from &quot;tinkering&quot; to &quot;engineering&quot; (the book&#39;s framing).</p></li><li><p><strong>Implement context isolation</strong> — running each agent as a subagent with its own context window prevents quality degradation in the reconciliation phase, which currently operates on the most polluted context.</p></li></ol><h3 id="prompt-maturity-assessment" tabindex="-1">Prompt maturity assessment <a class="header-anchor" href="#prompt-maturity-assessment" aria-label="Permalink to &quot;Prompt maturity assessment&quot;">​</a></h3><p>The workflow&#39;s skills sit at <strong>Level 4 (Contextual)</strong> on the book&#39;s 7-level Prompt Maturity Model. They read project context and produce structured output, but don&#39;t invoke other skills (Level 5), modify themselves based on outcomes (Level 6), or improve other skills (Level 7). The one-shot runner approaches Level 5 (Higher-Order) but isn&#39;t self-contained enough to qualify.</p><h3 id="what-was-excluded" tabindex="-1">What was excluded <a class="header-anchor" href="#what-was-excluded" aria-label="Permalink to &quot;What was excluded&quot;">​</a></h3><p>Several techniques in the book are not recommended for this workflow at this stage: A/B testing for prompts (research-oriented, not user-facing), Agent Teams / TeammateTool (experimental), automated CI/CD eval integration (overkill for a research site), and token-level cost tracking (requires API-level access not available in Cursor).</p>',15)])])}const m=t(i,[["render",s]]);export{p as __pageData,m as default};
